package day1;

public class Program3_DatatTypeExample {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
     boolean result=false; //boolean takes 1 bit
     System.out.println(result);
     // 1 byte is 8bits  -128 to +127 for age we can use this
     byte ans=-128;
     System.out.println(ans);
     
     // short takes 2 bytes -32000 to +32000 score for 0 t0 500
     short data=-32000;
     System.out.println(data);
     // char stores 1 char to mention gender or grade char takes 2 bytes it takes space,num,anyhing
     
     char alpha='A';
     System.out.println(alpha);
     
     //long stores 8 bytes for storing more than 10 digits
     long phoneNumber=9892345678L;
     System.out.println(phoneNumber);
     //4 bytes
     //7 floating points and sometimes round off
     float marks=91234.245674563F;
     System.out.println(marks);
    
     float marks1=91.245674563F;
     System.out.println(marks1);
     
     float marks2=9.245674563F;
     System.out.println(marks2);
     
     float marks3=916.245674563F;
     System.out.println(marks3);
     
     float marks4=99870.245674563F;
     System.out.println(marks4);
     
     //8 bytes 15 floating poimts
     double data3=9.123456789012345;
     System.out.println(data3);
     
     
     
     
     
	}

}
